#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;liburing.h&gt;

#define QUEUE_DEPTH 32

int main() {
    struct io_uring ring;

    // 1. Initialize the Ring Buffers
    if (io_uring_queue_init(QUEUE_DEPTH, &ring, 0) < 0) return 1;

    int fd = open("data.txt", O_RDONLY);

    // 2. Allocate memory on the HEAP (Stack memory is strictly forbidden for AIO)
    char *read_buffer = malloc(1024);

    // 3. Fetch an available slot in the Submission Queue
    struct io_uring_sqe *sqe = io_uring_get_sqe(&ring);

    // 4. Prepare a Read operation. 
    // This does NOT execute the read. It merely writes instructions to shared memory.
    io_uring_prep_read(sqe, fd, read_buffer, 1024, 0);

    // Attach a user-defined payload (like a callback or context struct) 
    // so we know which request finished when it pops out of the CQE.
    io_uring_sqe_set_data(sqe, (void *)12345);

    // 5. Submit the queue to the Kernel
    io_uring_submit(&ring);

    // ... Thread is free to do CPU math or submit 500 more requests ...

    // 6. Wait for the Kernel to finish the physical I/O
    struct io_uring_cqe *cqe;
    io_uring_wait_cqe(&ring, &cqe);

    if (cqe->res < 0) {
        fprintf(stderr, "Async read failed: %d\n", cqe->res);
    } else {
        printf("Async read complete. Payload ID: %lu. Bytes: %d\n", 
               (unsigned long)io_uring_cqe_get_data(cqe), cqe->res);
        printf("Data: %s\n", read_buffer);
    }

    // 7. Acknowledge to the Kernel that we have consumed this completion event
    io_uring_cqe_seen(&ring, cqe);

    io_uring_queue_exit(&ring);
    free(read_buffer);
    return 0;
}

#include &lt;sys/sendfile.h&gt;
#include &lt;sys/stat.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;

void serve_file_to_client(int client_socket_fd, const char *filepath) {
    int file_fd = open(filepath, O_RDONLY);
    if (file_fd < 0) return;

    struct stat stat_buf;
    fstat(file_fd, &stat_buf);
    size_t file_size = stat_buf.st_size;

    off_t offset = 0;
    size_t remaining = file_size;

    // Just like write(), sendfile() may only transfer a partial chunk if the 
    // network socket buffer fills up. A while loop is strictly mandatory.
    while (remaining > 0) {
        // The CPU mathematically executes NO array copies here.
        // It merely instructs the DMA controllers to route data internally.
        ssize_t sent = sendfile(client_socket_fd, file_fd, &offset, remaining);

        if (sent <= 0) {
            // Handle EAGAIN (Non-blocking sockets) or Client Disconnects
            break;
        }

        remaining -= sent;
    }

    close(file_fd);
}
